811:   MOZ_ASSERT(GetPresContext(), "Styling a document without a shell?");
812: 
813:   if (!mDocument->GetServoRestyleRoot()) {
814:     return false;
815:   }
816: 
817:   PreTraverse(aFlags);
818:   const SnapshotTable& snapshots = Snapshots();
819: 
820:   // Restyle the document from the root element and each of the document level
821:   // NAC subtree roots.
822:   bool postTraversalRequired = false;
823: 
824:   if (ShouldTraverseInParallel()) {
825:     aFlags |= ServoTraversalFlags::ParallelTraversal;
826:   }
827: 
828:   // Do the first traversal.
829:   DocumentStyleRootIterator iter(mDocument->GetServoRestyleRoot());
830:   while (Element* root = iter.GetNextStyleRoot()) {
831:     MOZ_ASSERT(MayTraverseFrom(root));
832: 
833:     Element* parent = root->GetFlattenedTreeParentElementForStyle();
834:     MOZ_ASSERT_IF(parent,
835:                   !parent->HasAnyOfFlags(Element::kAllServoDescendantBits));
836: 
837:     if (MOZ_UNLIKELY(!root->HasServoData()) && !parent) {
838:       StyleNewSubtree(root);
839:       postTraversalRequired = true;
840:       continue;
841:     }
842: 
843:     AutoPrepareTraversal guard(this);
844: 
845:     postTraversalRequired |=
846:         Servo_TraverseSubtree(root, mRawData.get(), &snapshots, aFlags) ||
847:         root->HasAnyOfFlags(Element::kAllServoDescendantBits |
848:                             NODE_NEEDS_FRAME);
849: 
850:     uint32_t existingBits = mDocument->GetServoRestyleRootDirtyBits();
851:     Element* newRoot = nullptr;
852:     while (parent && parent->HasDirtyDescendantsForServo()) {
853:       MOZ_ASSERT(root == mDocument->GetServoRestyleRoot(),
854:                  "Restyle root shouldn't have magically changed");
855:       // If any style invalidation was triggered in our siblings, then we may
856:       // need to post-traverse them, even if the root wasn't restyled after
857:       // all.
858:       // We need to propagate the existing bits to the ancestor.
859:       parent->SetFlags(existingBits);
860:       newRoot = parent;
861:       parent = parent->GetFlattenedTreeParentElementForStyle();
862:     }
863: 
864:     if (newRoot) {
865:       mDocument->SetServoRestyleRoot(
866:           newRoot, existingBits | ELEMENT_HAS_DIRTY_DESCENDANTS_FOR_SERVO);
867:       postTraversalRequired = true;
868:     }
869:   }
870: 
871:   // If there are still animation restyles needed, trigger a second traversal to
872:   // update CSS animations or transitions' styles.
873:   //
874:   // Note that we need to check the style root again, because doing another
875:   // PreTraverse on the EffectCompositor might alter the style root. But we
876:   // don't need to worry about NAC, since document-level NAC shouldn't have
877:   // animations.
878:   //
879:   // We don't need to do this for SMIL since SMIL only updates its animation
880:   // values once at the begin of a tick. As a result, even if the previous
881:   // traversal caused, for example, the font-size to change, the SMIL style
882:   // won't be updated until the next tick anyway.
883:   if (GetPresContext()->EffectCompositor()->PreTraverse(aFlags)) {
884:     DocumentStyleRootIterator iter(mDocument->GetServoRestyleRoot());
885:     while (Element* root = iter.GetNextStyleRoot()) {
886:       AutoPrepareTraversal guard(this);
887:       postTraversalRequired |=
888:           Servo_TraverseSubtree(root, mRawData.get(), &snapshots, aFlags) ||
889:           root->HasAnyOfFlags(Element::kAllServoDescendantBits |
890:                               NODE_NEEDS_FRAME);
891:     }
892:   }
893: 
894:   return postTraversalRequired;
895: }
