1170:     // InvalidateDescendants, because there can't be any
1171:     // out-of-flows or popups that need to be transformed; all out-of-flow
1172:     // descendants of the transformed element must also be descendants of the
1173:     // transformed frame.
1174:     InvalidateDescendants(
