1184:     if (aChange & nsChangeHint_RepaintFrame) {
1185:       // Note that this whole block will be skipped when painting is suppressed
1186:       // (due to our caller ApplyRendingChangeToTree() discarding the
1187:       // nsChangeHint_RepaintFrame hint).  If you add handling for any other
