1190:       needInvalidatingPaint = true;
1191:       aFrame->InvalidateFrameSubtree();
1192:       if ((aChange & nsChangeHint_UpdateEffects) &&
1193:           aFrame->HasAnyStateBits(NS_FRAME_SVG_LAYOUT)) {
