1268: static void ApplyRenderingChangeToTree(PresShell* aPresShell, nsIFrame* aFrame,
1269:                                        nsChangeHint aChange) {
1270:   // We check StyleDisplay()->HasTransformStyle() in addition to checking
1271:   // IsTransformed() since we can get here for some frames that don't support
1272:   // CSS transforms, and table frames, which are their own odd-ball, since the
1273:   // transform is handled by their wrapper, which _also_ gets a separate hint.
1274:   NS_ASSERTION(!(aChange & nsChangeHint_UpdateTransformLayer) ||
1275:                    aFrame->IsTransformed() ||
1276:                    aFrame->StyleDisplay()->HasTransformStyle(),
1277:                "Unexpected UpdateTransformLayer hint");
1278: 
1279:   if (aPresShell->IsPaintingSuppressed()) {
1280:     // Don't allow synchronous rendering changes when painting is turned off.
1281:     aChange &= ~nsChangeHint_RepaintFrame;
1282:     if (!aChange) {
1283:       return;
1284:     }
1285:   }
1286: 
1287: // Trigger rendering updates by damaging this frame and any
1288: // continuations of this frame.
1289: #ifdef DEBUG
1290:   gInApplyRenderingChangeToTree = true;
1291: #endif
1292:   if (aChange & nsChangeHint_RepaintFrame) {
1293:     // If the frame is the primary frame of either the body element or
1294:     // the html element, we propagate the repaint change hint to the
1295:     // viewport. This is necessary for background and scrollbar colors
1296:     // propagation.
1297:     if (aFrame->ShouldPropagateRepaintsToRoot()) {
1298:       nsIFrame* rootFrame = aPresShell->GetRootFrame();
1299:       MOZ_ASSERT(rootFrame, "No root frame?");
1300:       DoApplyRenderingChangeToTree(rootFrame, nsChangeHint_RepaintFrame);
1301:       aChange &= ~nsChangeHint_RepaintFrame;
1302:       if (!aChange) {
1303:         return;
1304:       }
1305:     }
1306:   }
1307:   DoApplyRenderingChangeToTree(aFrame, aChange);
1308: #ifdef DEBUG
1309:   gInApplyRenderingChangeToTree = false;
1310: #endif
1311: }
