8247: static void InvalidateFrameInternal(nsIFrame* aFrame, bool aHasDisplayItem,
8248:                                     bool aRebuildDisplayItems) {
8249:   if (aHasDisplayItem) {
8250:     aFrame->AddStateBits(NS_FRAME_NEEDS_PAINT);
8251:   }
8252: 
8253:   if (aRebuildDisplayItems) {
8254:     aFrame->MarkNeedsDisplayItemRebuild();
8255:   }
8256:   SVGObserverUtils::InvalidateDirectRenderingObservers(aFrame);
8257:   bool needsSchedulePaint = false;
8258:   if (nsLayoutUtils::IsPopup(aFrame)) {
8259:     needsSchedulePaint = true;
8260:   } else {
8261:     nsIFrame* parent = nsLayoutUtils::GetCrossDocParentFrameInProcess(aFrame);
8262:     while (parent &&
8263:            !parent->HasAnyStateBits(NS_FRAME_DESCENDANT_NEEDS_PAINT)) {
8264:       if (aHasDisplayItem && !parent->HasAnyStateBits(NS_FRAME_IS_NONDISPLAY)) {
8265:         parent->AddStateBits(NS_FRAME_DESCENDANT_NEEDS_PAINT);
8266:       }
8267:       SVGObserverUtils::InvalidateDirectRenderingObservers(parent);
8268: 
8269:       // If we're inside a popup, then we need to make sure that we
8270:       // call schedule paint so that the NS_FRAME_UPDATE_LAYER_TREE
8271:       // flag gets added to the popup display root frame.
8272:       if (nsLayoutUtils::IsPopup(parent)) {
8273:         needsSchedulePaint = true;
8274:         break;
8275:       }
8276:       parent = nsLayoutUtils::GetCrossDocParentFrameInProcess(parent);
8277:     }
8278:     if (!parent) {
8279:       needsSchedulePaint = true;
8280:     }
8281:   }
8282:   if (!aHasDisplayItem) {
8283:     return;
8284:   }
8285:   if (needsSchedulePaint) {
8286:     nsIFrame* displayRoot = nsLayoutUtils::GetDisplayRootFrame(aFrame);
8287:     SchedulePaintInternal(displayRoot, aFrame);
8288:   }
8289:   if (aFrame->HasAnyStateBits(NS_FRAME_HAS_INVALID_RECT)) {
8290:     aFrame->RemoveProperty(nsIFrame::InvalidationRect());
8291:     aFrame->RemoveStateBits(NS_FRAME_HAS_INVALID_RECT);
8292:   }
8293: }
